class Solution:
    def new21Game(self, n: int, k: int, maxPts: int) -> float:
        if k == 0:
            return 1.0

        dp = [0.0] * (n + 1)
        dp[0] = 1.0

        pre_sum = [0.0] * (n + 1)
        pre_sum[0] = dp[0]

        for i in range(1, n + 1):
            if i < k:
                a = max(0, i - maxPts)
                b = i - 1
            else:
                a = max(0, i - maxPts)
                b = min(k - 1, i - 1)

            if a == 0:
                sum_val = pre_sum[b]
            else:
                sum_val = pre_sum[b] - pre_sum[a - 1]

            dp[i] = sum_val / maxPts
            pre_sum[i] = pre_sum[i - 1] + dp[i]

        result = sum(dp[k : n + 1])
        return result

